const final = {};
let mensagens = [];

for (const item of items) {
  const json = item.json;

  // Junta mensagens
  if (json.Mensagem) {
    mensagens.push(json.Mensagem);
  }

  // Copia os demais campos (sem sobrescrever mensagens)
  for (const key in json) {
    if (key !== 'Mensagem') {
      final[key] = json[key];
    }
  }

  // Extrai o telefone diretamente do From do WhatsApp
  // O WhatsApp já normaliza o número no formato correto:
  //   BR: 5571993643490  (55 + DDD + 9 + número)
  //   ARG: 5491160000000 (54 + 9 + area + número)
  // Esse formato é idêntico ao salvo na planilha durante a mineração.
  if (json.From && !final.telefone) {
    final.telefone = json.From.split('@')[0];
  }
}

final.Mensagem = mensagens.join('\n');

return [{ json: final }];

